        q_pre.FreeTensor(preLocal);
        q_hNext.FreeTensor(hNextLocal);
        q_y.FreeTensor(yLocal);
        q_w1.FreeTensor(w1Local);
        q_w2.FreeTensor(w2Local);
        q_b1.FreeTensor(b1Local);
        q_b2.FreeTensor(b2Local);
        q_tmp.FreeTensor(tmpLocal);
